  auto getMissingCase = [&](SmallVectorImpl<ConstantInt *> &Cases) -> ConstantInt * {
    if (Cases.empty()) return nullptr;
    array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);
    ConstantInt *Missing = nullptr;
    for (size_t I = 1, E = Cases.size(); I != E; ++I) {
      if (Cases[I - 1]->getValue() + 1 == Cases[I]->getValue())
        continue;
      if (Cases[I - 1]->getValue() + 2 == Cases[I]->getValue() && !Missing) {
        Missing = cast<ConstantInt>(ConstantInt::get(Cases[0]->getType(), Cases[I - 1]->getValue() + 1));
        continue;
      }
      return nullptr;
    }
    return Missing;
  };

  auto getComplementContiguous = [&](SmallVectorImpl<ConstantInt *> &Cases, SmallVectorImpl<ConstantInt *> &Complement) {
    SimplifyQuery Q(DL, SI);
    Q.AC = Options.AC;
    ConstantRange CR = computeConstantRange(SI->getCondition(), true, true, Options.AC, SI, nullptr, 0);
    if (CR.isFullSet() || CR.isEmptySet())
      return false;
    // Don't iterate over a huge range
    if (CR.getSetSize().ugt(64))
      return false;

    array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);

    APInt End = CR.getUpper();
    for (APInt I = CR.getLower(); I != End; ++I) {
      ConstantInt *CI = cast<ConstantInt>(ConstantInt::get(SI->getCondition()->getType(), I));
      auto It = std::lower_bound(Cases.begin(), Cases.end(), CI, [](ConstantInt *A, ConstantInt *B) {
        return A->getValue().ult(B->getValue());
      });
      if (It == Cases.end() || (*It)->getValue() != I) {
        Complement.push_back(CI);
      }
    }
    return casesAreContiguous(Complement);
  };

  // Figure out if one of the sets of cases form a contiguous range.
  SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
  BasicBlock *ContiguousDest = nullptr;
  BasicBlock *OtherDest = nullptr;
  ConstantInt *MissingCase = nullptr;
  SmallVector<ConstantInt *, 16> ComplementA;
  SmallVector<ConstantInt *, 16> ComplementB;

  if (casesAreContiguous(CasesA)) {
    ContiguousCases = &CasesA;
    ContiguousDest = DestA;
    OtherDest = DestB;
  } else if (casesAreContiguous(CasesB)) {
    ContiguousCases = &CasesB;
    ContiguousDest = DestB;
    OtherDest = DestA;
  } else if (getComplementContiguous(CasesA, ComplementA)) {
    ContiguousCases = &ComplementA;
    ContiguousDest = DestB;
    OtherDest = DestA;
  } else if (getComplementContiguous(CasesB, ComplementB)) {
    ContiguousCases = &ComplementB;
    ContiguousDest = DestA;
    OtherDest = DestB;
  } else if ((MissingCase = getMissingCase(CasesA))) {
    ContiguousCases = &CasesA;
    ContiguousDest = DestA;
    OtherDest = DestB;
  } else if ((MissingCase = getMissingCase(CasesB))) {
    ContiguousCases = &CasesB;
    ContiguousDest = DestB;
    OtherDest = DestA;
  } else
    return false;
